app.post('/authorize', async (req, res) => {
  const { client_id, redirect_uri, scope, state, username, password } = req.body;
  
  if (!username || typeof username !== 'string' || username.length > 128) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  if (!password || typeof password !== 'string' || password.length > 256) {
    return res.status(400).json({ error: 'invalid_request' });
  }
  
  let user = null;
  for (const u of USERS_DB.values()) {
    if (u.username === username && bcrypt.compareSync(password, u.password)) {
      user = u;
      break;
    }
  }
  
  if (!user) {
    return res.status(401).json({ error: 'access_denied' });
  }
  
  const client = CLIENTS_DB.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }
  
  if (!validateRedirectUri(client_id, redirect_uri)) {
    return res.status(400).json({ error: 'invalid_redirect_uri' });
  }
  
  const authCode = generateAuthorizationCode();
  const codeData = {
    clientId: client_id,
    userId: user.userId,
    redirectUri: redirect_uri,
    scope: scope || '',
    expiresAt: Date.now() + 600000
  };
  
  await setexAsync(`authcode:${authCode}`, 600, JSON.stringify(codeData));
  
  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.set('code', authCode);
  if (state) {
    redirectUrl.searchParams.set('state', state);
  }
  
  res.redirect(redirectUrl.toString());
});

app.post('/token', async (req, res) => {
  const { grant_type, code, redirect_uri, refresh_token, client_id, client_secret } = req.body;
  
  if (!client_id || !client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  if (!validateClientCredentials(client_id, client_secret)) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  if (grant_type === 'authorization_code') {
    if (!code || typeof code !== 'string' || code.length > 256) {
      return res.status(400).json({ error: 'invalid_request' });
    }
    
    const codeDataStr = await getAsync(`authcode:${code}`);
    if (!codeDataStr) {
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    const codeData = JSON.parse(codeDataStr);
    
    if (codeData.clientId !== client_id) {
      await delAsync(`authcode:${code}`);
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    if (codeData.redirectUri !== redirect_uri) {
      await delAsync(`authcode:${code}`);
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    if (codeData.expiresAt < Date.now()) {
      await delAsync(`authcode:${code}`);
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    await delAsync(`authcode:${code}`);
    
    const accessToken = generateSecureToken();
    const refreshToken = generateSecureToken();
    
    const accessTokenData = {
      clientId: client_id,
      userId: codeData.userId,
      scope: codeData.scope,
      expiresAt: Date.now() + (ACCESS_TOKEN_TTL * 1000)
    };
    
    const refreshTokenData = {
      clientId: client_id,
      userId: codeData.userId,
      scope: codeData.scope,
      expiresAt: Date.now() + (REFRESH_TOKEN_TTL * 1000)
    };
    
    await setexAsync(`access:${accessToken}`, ACCESS_TOKEN_TTL, JSON.stringify(accessTokenData));
    await setexAsync(`refresh:${refreshToken}`, REFRESH_TOKEN_TTL, JSON.stringify(refreshTokenData));
    
    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: ACCESS_TOKEN_TTL,
      refresh_token: refreshToken,
      scope: codeData.scope
    });
    
  } else if (grant_type === 'refresh_token') {
    if (!refresh_token || typeof refresh_token !== 'string' || refresh_token.length > 256) {
      return res.status(400).json({ error: 'invalid_request' });
    }
    
    const refreshTokenDataStr = await getAsync(`refresh:${refresh_token}`);
    if (!refreshTokenDataStr) {
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    const refreshTokenData = JSON.parse(refreshTokenDataStr);
    
    if (refreshTokenData.clientId !== client_id) {
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    if (refreshTokenData.expiresAt < Date.now()) {
      await delAsync(`refresh:${refresh_token}`);
      return res.status(400).json({ error: 'invalid_grant' });
    }
    
    const newAccessToken = generateSecureToken();
    
    const accessTokenData = {
      clientId: client_id,
      userId: refreshTokenData.userId,
      scope: refreshTokenData.scope,
      expiresAt: Date.now() + (ACCESS_TOKEN_TTL * 1000)
    };
    
    await setexAsync(`access:${newAccessToken}`, ACCESS_TOKEN_TTL, JSON.stringify(accessTokenData));
    
    return res.json({
      access_token: newAccessToken,
      token_type: 'Bearer',
      expires_in: ACCESS_TOKEN_TTL,
      refresh_token: refresh_token,
      scope: refreshTokenData.scope
    });
    
  } else {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }
});

app.get('/userinfo', async (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  const token = authHeader.substring(7);
  
  if (!token || typeof token !== 'string' || token.length > 256) {
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  const tokenDataStr = await getAsync(`access:${token}`);
  if (!tokenDataStr) {
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  const tokenData = JSON.parse(tokenDataStr);
  
  if (tokenData.expiresAt < Date.now()) {
    await delAsync(`access:${token}`);
    return res.status(401).json({ error: 'invalid_token' });
  }
  
  const user = USERS_DB.get(tokenData.userId);
  if (!user) {
    return res.status(404).json({ error: 'user_not_found' });
  }
  
  return res.json({
    sub: user.userId,
    username: user.username,
    email: user.email
  });
});

app.post('/revoke', async (req, res) => {
  const { token, token_type_hint, client_id, client_secret } = req.body;
  
  if (!client_id || !client_secret) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  if (!validateClientCredentials(client_id, client_secret)) {
    return res.status(401).json({ error: 'invalid_client' });
  }
  
  if (!token || typeof token !== 'string' || token.length > 256) {
    return res.status(200).send();
  }
  
  if (token_type_hint === 'refresh_token') {
    await delAsync(`refresh:${token}`);
  } else if (token_type_hint === 'access_token') {
    await delAsync(`access:${token}`);
  } else {
    await delAsync(`refresh:${token}`);
    await delAsync(`access:${token}`);
  }
  
  return res.status(200).send();
});

